#version 300 es
                precision highp float;
                in vec2 vTextureCoord;
                uniform sampler2D uTexture;
                uniform float uTime;

                vec3 getColor(int index) {
                    switch(index) {
                        case 0: return vec3(0, 0, 0);
                        case 1: return vec3(0.082, 0.082, 0.082);
                        case 2: return vec3(0.0, 0.3, 0.8);  // Blauw
                        case 3: return vec3(0.0, 0.5, 1.0);  // Blauw
                        case 4: return vec3(0.0, 0.6, 1.0);  // Blauw
                        case 5: return vec3(0, 0, 0);
                        default: return vec3(0.0);
                    }
                }

                vec3 getGradientColor(float position) {
                    for (int i = 0; i < 5; i++) {
                        float colorPosition = float(i) / float(5);
                        float nextColorPosition = float(i + 1) / float(5);
                        if (position <= nextColorPosition) {
                            float mixFactor = (position - colorPosition) / (nextColorPosition - colorPosition);
                            vec3 linStart = getColor(i);
                            vec3 linEnd = getColor(i + 1);
                            return mix(linStart, linEnd, mixFactor);
                        }
                    }
                    return getColor(4);
                }

                out vec4 fragColor;

                void main() {
                    vec2 uv = vTextureCoord;
                    vec4 color = texture(uTexture, uv);
                    float position = smoothstep(0., 1., color.r) * (0.40 * 2.);
                    float posOffset = (dot(vec2(0.5, 0.5), vec2(0.5, 0.5)) + 0.22 + 0.0001) * 2.;
                    position -= (uTime * 0.01 + posOffset);
                    float animatedPos = fract(position);
                    animatedPos = clamp(animatedPos, 0. - 1. / float(5), 1.0);
                    color.rgb = getGradientColor(animatedPos);
                    fragColor = color;
                }
